// ------------------------------------------------------------
//  Expected Difference – solution in C (NTT)
// ------------------------------------------------------------
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#define MOD 998244353
#define G   3

static int mod_pow(int a, long long e) {
    long long r = 1, x = a;
    while (e) {
        if (e & 1) r = r * x % MOD;
        x = x * x % MOD;
        e >>= 1;
    }
    return (int)r;
}

static void ntt(int *a, int n, int invert) {
    static int rev[1 << 20];
    static int roots[1 << 20];
    int logn = 0; while ((1 << logn) < n) ++logn;
    for (int i = 0; i < n; ++i) {
        rev[i] = (rev[i>>1]>>1) | ((i&1) << (logn-1));
        if (i < rev[i]) {
            int tmp = a[i]; a[i] = a[rev[i]]; a[rev[i]] = tmp;
        }
    }
    for (int len = 2, step = 1; len <= n; len <<= 1, ++step) {
        int wlen = mod_pow(G, (MOD-1) / len);
        if (invert) wlen = mod_pow(wlen, MOD-2);
        for (int i = 0; i < n; i += len) {
            int w = 1;
            for (int j = 0; j < len/2; ++j) {
                int u = a[i+j];
                int v = (int)((long long)a[i+j+len/2] * w % MOD);
                a[i+j] = u + v < MOD ? u + v : u + v - MOD;
                a[i+j+len/2] = u - v >= 0 ? u - v : u - v + MOD;
                w = (int)((long long)w * wlen % MOD);
            }
        }
    }
    if (invert) {
        int inv_n = mod_pow(n, MOD-2);
        for (int i = 0; i < n; ++i) a[i] = (int)((long long)a[i] * inv_n % MOD);
    }
}

static int *multiply(const int *a, int na, const int *b, int nb, int limit, int *out_len) {
    int need = na + nb - 1;
    int n = 1; while (n < need) n <<= 1;
    int *fa = (int*)calloc(n, sizeof(int));
    int *fb = (int*)calloc(n, sizeof(int));
    memcpy(fa, a, na * sizeof(int));
    memcpy(fb, b, nb * sizeof(int));
    ntt(fa, n, 0);
    ntt(fb, n, 0);
    for (int i = 0; i < n; ++i) fa[i] = (int)((long long)fa[i] * fb[i] % MOD);
    ntt(fa, n, 1);
    int sz = need > limit+1 ? limit+1 : need;
    int *res = (int*)malloc(sz * sizeof(int));
    for (int i = 0; i < sz; ++i) res[i] = fa[i];
    free(fa); free(fb);
    *out_len = sz;
    return res;
}

static int *solve_range(int *arr, int l, int r, int X, int *len) {
    if (l == r) {
        int sz = arr[l] + 1;
        if (sz > X+1) sz = X+1;
        int *poly = (int*)calloc(sz, sizeof(int));
        poly[0] = 1;
        if (arr[l] <= X) poly[arr[l]] = 1;
        *len = sz;
        return poly;
    }
    int m = (l + r) >> 1;
    int len1, len2;
    int *p1 = solve_range(arr, l, m, X, &len1);
    int *p2 = solve_range(arr, m+1, r, X, &len2);
    int *res = multiply(p1, len1, p2, len2, X, len);
    free(p1); free(p2);
    return res;
}

int main(){
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int X, N; scanf("%d %d", &X, &N);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i=0;i<N;++i) scanf("%d", &A[i]);
        int poly_len;
        int *poly = solve_range(A, 0, N-1, X, &poly_len);
        long long sum = 0;
        for (int s=0; s<poly_len; ++s) {
            int coeff = poly[s];
            int diff = 2*s - X; if (diff<0) diff = -diff;
            sum = (sum + (long long)coeff * diff) % MOD;
        }
        int pow2 = mod_pow(2, N);
        int inv_pow2 = mod_pow(pow2, MOD-2);
        int ans = (int)(sum * inv_pow2 % MOD);
        printf("%d\n", ans);
        free(poly); free(A);
    }
    return 0;
}

